<script lang="ts">import PageHeader from '$lib/components/PageHeader.svelte'; import StatusBadge from '$lib/components/StatusBadge.svelte'; import { orders, money } from '$lib/data'; import { Download, Sheet } from 'lucide-svelte'; async function exportXlsx(){const XLSX=await import('xlsx');const rows=orders.map(o=>({Invoice:'INV-'+o.id.slice(-4),Project:o.project,Customer:o.customer,Total:o.price,Paid:o.paid,Balance:o.price-o.paid,Status:o.paid===o.price?'Paid':o.paid?'Partially paid':'Unpaid'}));const wb=XLSX.utils.book_new();XLSX.utils.book_append_sheet(wb,XLSX.utils.json_to_sheet(rows),'Invoices');XLSX.writeFile(wb,'studioflow-invoices.xlsx')}</script>
<PageHeader eyebrow="Bills and payment tracking" title="Invoices" action="New invoice" />
<div class="invoice-summary"><div><span>Outstanding</span><strong>{money(37500)}</strong></div><div><span>Collected this month</span><strong>{money(64200)}</strong></div><button class="secondary" onclick={exportXlsx}><Download size={13}/> Export .xlsx</button></div>
<div class="card table-wrap"><table class="data-table"><thead><tr><th>Invoice</th><th>Customer</th><th>Total</th><th>Paid</th><th>Balance</th><th>Status</th></tr></thead><tbody>{#each orders as order}<tr><td><strong>INV-{order.id.slice(-4)}</strong><small>{order.project}</small></td><td>{order.customer}</td><td>{money(order.price)}</td><td>{money(order.paid)}</td><td>{money(order.price-order.paid)}</td><td><StatusBadge status={order.paid===order.price?'Paid':order.paid?'Partially paid':'Unpaid'}/></td></tr>{/each}</tbody></table></div>
<div class="sheet-note"><Sheet size={14}/><span>Payment changes are written to Google Sheets immediately.</span></div>
<style>.invoice-summary{display:flex;gap:30px;align-items:center;margin-bottom:18px;padding:0 2px}.invoice-summary>div{display:flex;flex-direction:column;gap:5px}.invoice-summary span{font-size:9px;color:#6e7989;text-transform:uppercase;letter-spacing:.06em}.invoice-summary strong{font-size:18px}.invoice-summary button{margin-left:auto;display:flex;gap:7px;align-items:center}.sheet-note{display:flex;gap:7px;align-items:center;margin-top:12px;color:#647083;font-size:9px}@media(max-width:600px){.invoice-summary>div:nth-child(2){display:none}}</style>
